request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop (COUNT(*) as ?count) WHERE {
  {
    ?elem vocab:NamedElement_name "Executive Software" .
    ?elem ?prop ?value .
  }
  UNION
  {
    ?elem vocab:NamedElement_name "Procedure Executive and Analysis Software" .
    ?elem ?prop ?value .
  }
}
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25
